#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int a[1000];
        for(int i=0;i<n;++i) scanf("%d",&a[i]);
        int leaders[1000]; int cnt=0;
        int maxRight=a[n-1];
        leaders[cnt++]=maxRight;
        for(int i=n-2;i>=0;--i){
            if(a[i]>maxRight){
                maxRight=a[i];
                leaders[cnt++]=maxRight;
            }
        }
        for(int i=cnt-1;i>=0;--i){
            printf("%d",leaders[i]);
            if(i) printf(" ");
        }
        printf("
");
    }
    return 0;
}

