const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
if(data.length===0) process.exit(0);
const T=parseInt(data[idx++],10);
let outputs=[];
for(let t=0;t<T;++t){
  const n=parseInt(data[idx++],10);
  const arr=[];
  for(let i=0;i<n;++i) arr.push(parseInt(data[idx++],10));
  const leaders=[];
  let maxRight=arr[n-1];
  leaders.push(maxRight);
  for(let i=n-2;i>=0;--i){
    if(arr[i]>maxRight){
      maxRight=arr[i];
      leaders.push(maxRight);
    }
  }
  outputs.push(leaders.reverse().join(' '));
}
process.stdout.write(outputs.join('\n'));
